 1	import type { FC } from 'react';
 2	
 3	import { nameColumn } from '@components/VsphereFoldersTable/utils/constants';
 4	import type { FolderRow } from '@components/VsphereFoldersTable/utils/types';
 5	import { Td, TreeRowWrapper } from '@patternfly/react-table';
 6	
 7	import FolderNameCell from './FolderNameCell';
 8	
 9	type FolderTreeRowProps = {
10	  row: FolderRow;
11	  groupVMCountByFolder: Map<string, number>;
12	};
13	
14	const FolderTreeRow: FC<FolderTreeRowProps> = ({ groupVMCountByFolder, row }) => {
15	  return (
16	    <TreeRowWrapper data-testid={row.key} key={row.key} row={{ props: row?.treeRow?.props }}>
17	      <Td treeRow={row.treeRow} dataLabel={nameColumn.label}>
18	        <FolderNameCell row={row} vmCount={groupVMCountByFolder.get(row.folderName) ?? 0} />
19	      </Td>
20	    </TreeRowWrapper>
21	  );
22	};
23	
24	export default FolderTreeRow;

